#include <bits/stdc++.h>
using namespace std;
int main() {
    int dividend, divisor;
    cin >> dividend >> divisor;
    int MIN_INT = -2147483648, MAX_INT = 2147483647;
    int sign = (dividend < 0) ^ (divisor < 0) ? -1 : 1;
    long long abs_dividend = abs((long long)dividend);
    long long abs_divisor = abs((long long)divisor);
    long long quotient = 0;
    while (abs_dividend >= abs_divisor) {
        int shift = 0;
        while ((abs_divisor << shift) <= abs_dividend) {
            shift++;
        }
        shift--;
        abs_dividend -= (abs_divisor << shift);
        quotient += (1LL << shift);
    }
    quotient *= sign;
    if (quotient < MIN_INT) {
        cout << MIN_INT << endl;
    } else if (quotient > MAX_INT) {
        cout << MAX_INT << endl;
    } else {
        cout << quotient << endl;
    }
    return 0;
}
